import { apiClient } from '../utils/apiClient';

export const authService = {
  register(payload) {
    return apiClient.post('/auth/register', payload);
  },
  login(payload) {
    return apiClient.post('/auth/login', payload);
  },
  sendOTP(email, purpose) {
    return apiClient.post('/auth/send-otp', { email, purpose });
  },
  verifyOTP(email, otp, purpose) {
    return apiClient.post('/auth/verify-otp', { email, otp, purpose });
  },
  me(token) {
    return apiClient.get('/auth/me', { token });
  },
  getUserProfile() {
    return apiClient.get('/auth/me');
  },
  updateUserProfile(data) {
    return apiClient.patch('/auth/me', data);
  }
};

export const getUserProfile = () => authService.getUserProfile();
export const updateUserProfile = (data) => authService.updateUserProfile(data);
export const sendOTP = (email, purpose) => authService.sendOTP(email, purpose);
export const verifyOTP = (email, otp, purpose) => authService.verifyOTP(email, otp, purpose);
